function App() {
  const [messages, setMessages] = useState<Message[]>([]);
  const [artifacts, setArtifacts] = useState<Artifact[]>([]);
  const [inputText, setInputText] = useState('');
  const [mode, setMode] = useState<ReasoningMode>('flash');
  const [isProcessing, setIsProcessing] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isMonitorOpen, setIsMonitorOpen] = useState(false);
  const [securityStatus, setSecurityStatus] = useState<'idle' | 'scanning' | 'safe' | 'alert'>('idle');
  const [systemMetrics, setSystemMetrics] = useState({ cpu: 8, ram: 42, latency: 98, uptime: '00:00:00' });
  const [logs, setLogs] = useState<{ t: number, m: string, s: 'info'|'warn'|'error'|'sec'|'rust' }[]>([]);
  const [agents, setAgents] = useState<AgentState[]>([
    { id: 'RUST_CORE', name: 'Rust Reasoning Core', status: 'IDLE', load: 0 },
    { id: 'OPA_SEC', name: 'OPA Security Gate', status: 'IDLE', load: 0 },
    { id: 'MM_PARSER', name: 'Multimodal Parser', status: 'IDLE', load: 0 },
    { id: 'SYNTH_ENGINE', name: 'Synthesis Engine', status: 'IDLE', load: 0 },
    { id: 'SEARCH_RETRIEVAL', name: 'Search & Retrieval', status: 'IDLE', load: 0 }
  ]);

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const startTime = useRef(Date.now());

  useEffect(() => {
    loadArtifacts();
    addLog('NEXUS Distributed Core V4.2 Initialized', 'rust');
    addLog('Rust-Memory-Safety mechanisms active', 'rust');
    addLog('OPA Policy Engine v3.1.2 Loaded', 'sec');

    const interval = setInterval(() => {
        const diff = Date.now() - startTime.current;
        const h = Math.floor(diff / 3600000).toString().padStart(2, '0');
        const m = Math.floor((diff % 3600000) / 60000).toString().padStart(2, '0');
        const s = Math.floor((diff % 60000) / 1000).toString().padStart(2, '0');

        setSystemMetrics(prev => ({
            cpu: Math.floor(Math.random() * 8) + 4,
            ram: 41 + (Math.sin(diff / 8000) * 1.5),
            latency: 90 + Math.floor(Math.random() * 30),
            uptime: `${h}:${m}:${s}`
        }));

        if (Math.random() > 0.92) {
            const rustLogs = [
                'Borrow checker validation: OK',
                'Zero-copy buffer swap executed',
                'Microservice handshake: RUST_CORE -> SYNTH_ENGINE',
                'Ownership transfer complete for chunk_0x24F',
                'Concurrency pool optimized for thread_id: 8'
            ];
            addLog(rustLogs[Math.floor(Math.random() * rustLogs.length)], 'rust');
        }
    }, 1500);
    return () => clearInterval(interval);
  }, []);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const addLog = (m: string, s: 'info'|'warn'|'error'|'sec'|'rust' = 'info') => {
      setLogs(prev => [{ t: Date.now(), m, s }, ...prev].slice(0, 100));
  };

  const updateAgent = (id: AgentId, status: 'IDLE' | 'ACTIVE' | 'ERROR', load: number) => {
      setAgents(prev => prev.map(a => a.id === id ? { ...a, status, load } : a));
  };

  const loadArtifacts = async () => {
    const items = await DBService.getAllArtifacts();
    setArtifacts(items);
  };

  const handleSendMessage = async () => {
    if (!inputText.trim() || isProcessing) return;

    setIsProcessing(true);
    setSecurityStatus('scanning');

    // START PIPELINE
    updateAgent('OPA_SEC', 'ACTIVE', 100);
    addLog(`[OPA] Inspecting request payload...`, 'sec');

    const securityCheck = await SecurityService.validateInput(inputText);

    if (securityCheck.status === 'MALICIOUS') {
        updateAgent('OPA_SEC', 'ERROR', 0);
        setSecurityStatus('alert');
        addLog(`SECURITY ALERT: Malicious pattern intercepted by Rust-Core`, 'error');
        setMessages(prev => [...prev, {
            id: Date.now().toString(),
            role: 'model',
            text: `### 🔴 ACCESS DENIED\n\nNEXUS Core detected an injection attempt. The request has been sanitized and discarded to prevent heap corruption.`,
            timestamp: Date.now()
        }]);
        setIsProcessing(false);
        return;
    }

    updateAgent('OPA_SEC', 'IDLE', 0);
    updateAgent('RUST_CORE', 'ACTIVE', 85);
    updateAgent('MM_PARSER', artifacts.length > 0 ? 'ACTIVE' : 'IDLE', 40);
    setSecurityStatus('safe');
    addLog('[RUST] Task allocated to synthesis pool', 'rust');

    const userMsg: Message = {
      id: Date.now().toString(),
      role: 'user',
      text: inputText,
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, userMsg]);
    setInputText('');

    try {
      updateAgent('SYNTH_ENGINE', 'ACTIVE', 95);
      if (mode === 'flash') updateAgent('SEARCH_RETRIEVAL', 'ACTIVE', 60);

      const responseText = await GeminiService.generateResponse(
        messages,
        artifacts,
        mode,
        userMsg.text
      );

      const botMsg: Message = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: responseText,
        timestamp: Date.now()
      };

      setMessages(prev => [...prev, botMsg]);
      addLog(`[RUST] Kernel cycle complete in ${mode} mode`, 'rust');
    } catch (error: any) {
      addLog(`Distributed system error: ${error.message}`, 'error');
    } finally {
      setIsProcessing(false);
      setAgents(prev => prev.map(a => ({ ...a, status: 'IDLE', load: 0 })));
      setTimeout(() => setSecurityStatus('idle'), 3000);
    }
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;
    updateAgent('MM_PARSER', 'ACTIVE', 100);

    for (let i = 0; i < files.length; i++) {
      const file = files[i];
      addLog(`Ingesting artifact via zero-copy: ${file.name}`, 'rust');
      const reader = new FileReader();

      reader.onload = async (ev) => {
        const result = ev.target?.result as string;
        let type: Artifact['type'] = 'text';
        let content = result;

        if (file.type.startsWith('image/')) {
            type = 'image';
            content = result.split(',')[1];
        } else if (file.type === 'text/csv' || file.name.endsWith('.csv')) {
            type = 'csv';
        }

        const newArtifact: Artifact = {
          id: Date.now().toString() + Math.random().toString(),
          name: file.name,
          type,
          content,
          mimeType: file.type,
          createdAt: Date.now()
        };

        await DBService.saveArtifact(newArtifact);
        setArtifacts(prev => [...prev, newArtifact]);
        addLog(`Vaulted: ${newArtifact.name}`, 'sec');
        updateAgent('MM_PARSER', 'IDLE', 0);
      };

      if (file.type.startsWith('image/')) {
        reader.readAsDataURL(file);
      } else {
        reader.readAsText(file);
      }
    }
  };

  return (
    <div className="flex h-[100dvh] w-full bg-[#030303] text-zinc-300 font-sans overflow-hidden relative selection:bg-aegis-accent/30 selection:text-white">

      {/* Background Ambience */}
      <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,_rgba(0,112,243,0.03)_0%,_transparent_70%)] pointer-events-none" />
      <div className="scan-line" />

      {/* MOBILE OVERLAY */}
      {(isSidebarOpen || (isMonitorOpen && window.innerWidth < 1024)) && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-md z-[60] lg:hidden" onClick={() => { setIsSidebarOpen(false); setIsMonitorOpen(false); }} />
      )}

      {/* LEFT SIDEBAR: Context Memory */}
      <div className={`
        fixed inset-y-0 left-0 z-[70] w-[80%] sm:w-64 glass border-r border-white/5 flex flex-col transform transition-all duration-300 ease-in-out
        ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'} md:relative md:translate-x-0
      `}>
        <div className="p-4 border-b border-white/5 bg-black/20 flex items-center justify-between">
            <div className="flex items-center gap-2">
                <Box size={14} className="text-aegis-accent" />
                <span className="text-[10px] font-bold tracking-[0.2em] font-mono text-zinc-500 uppercase">Context_Vault</span>
            </div>
            <button onClick={() => fileInputRef.current?.click()} className="p-1.5 hover:bg-white/5 rounded-md text-zinc-400">
                <Plus size={16} />
            </button>
            <input type="file" ref={fileInputRef} className="hidden" multiple onChange={handleFileUpload} />
        </div>

        <div className="flex-1 overflow-y-auto p-3 space-y-2 custom-scrollbar">
            {artifacts.map(art => (
                <div key={art.id} className="group glass border border-white/5 rounded-lg p-3 hover:border-aegis-accent/30 transition-all cursor-default relative overflow-hidden">
                    <div className="flex items-center gap-2 mb-1.5">
                        <Fingerprint size={12} className="text-aegis-accent/60" />
                        <span className="text-[11px] font-mono font-bold truncate tracking-tight">{art.name}</span>
                    </div>
                    <div className="flex justify-between items-center text-[9px] font-mono text-zinc-500">
                        <span className="opacity-50 uppercase">{art.type}</span>
                        <button onClick={() => DBService.deleteArtifact(art.id).then(loadArtifacts)} className="opacity-0 group-hover:opacity-100 p-1 text-zinc-600 hover:text-aegis-error transition-opacity">
                            <X size={10} />
                        </button>
                    </div>
                </div>
            ))}
        </div>
      </div>

      {/* MAIN WORKSPACE */}
      <div className="flex-1 flex flex-col min-w-0 relative">

        {/* HEADER */}
        <div className="h-14 border-b border-white/5 flex items-center justify-between px-4 sm:px-6 bg-black/40 backdrop-blur-xl z-50">
            <div className="flex items-center gap-4">
                <button className="md:hidden text-zinc-500" onClick={() => setIsSidebarOpen(true)}>
                    <Menu size={20} />
                </button>
                <div className="flex flex-col">
                    <div className="flex items-center gap-2">
                        <div className="w-2 h-2 rounded-full bg-aegis-accent shadow-[0_0_8px_#0070f3] animate-pulse" />
                        <h1 className="text-[10px] font-black tracking-[0.4em] font-mono uppercase">Nexus_Distributed</h1>
                    </div>
                    <span className="text-[8px] font-mono text-zinc-600 uppercase ml-4">Rust-Core v4.28 // OPA-Enabled</span>
                </div>
            </div>

            <div className="flex items-center gap-3">
                <div className="hidden sm:flex bg-zinc-900/50 p-1 rounded-lg border border-white/5">
                    <button onClick={() => setMode('flash')} className={`px-2.5 py-1 rounded-md text-[9px] font-bold uppercase transition-all ${mode === 'flash' ? 'bg-aegis-accent/10 text-aegis-accent' : 'text-zinc-600'}`}>Flash</button>
                    <button onClick={() => setMode('pro')} className={`px-2.5 py-1 rounded-md text-[9px] font-bold uppercase transition-all ${mode === 'pro' ? 'bg-aegis-accent/10 text-aegis-accent' : 'text-zinc-600'}`}>Pro</button>
                </div>
                <button onClick={() => setIsMonitorOpen(!isMonitorOpen)} className={`p-2 rounded-lg transition-all ${isMonitorOpen ? 'text-aegis-accent bg-aegis-accent/10' : 'text-zinc-500'}`}>
                    <Activity size={18} />
                </button>
            </div>
        </div>

        {/* MESSAGES */}
        <div className="flex-1 overflow-y-auto p-4 sm:p-8 space-y-10 custom-scrollbar">
            {messages.length === 0 && (
                <div className="flex flex-col items-center justify-center min-h-[60vh] text-center">
                    <div className="w-20 h-20 bg-aegis-accent/5 border border-aegis-accent/10 rounded-2xl flex items-center justify-center mb-6 relative group overflow-hidden">
