                    <div className={`max-w-[85%] md:max-w-2xl lg:max-w-3xl space-y-3 ${msg.role === 'user' ? 'items-end' : ''}`}>
                        <div className={`px-5 py-4 rounded-2xl text-[14px] leading-relaxed border ${msg.role === 'user' ? 'bg-zinc-900 border-zinc-700 text-zinc-100' : 'bg-[#0a0a0b]/80 border-white/5 text-zinc-300'}`}>
