            {/* RUST LOGS */}
            <div className="space-y-3">
                <div className="flex justify-between items-center">
                    <h3 className="text-[9px] font-bold font-mono text-zinc-600 uppercase tracking-widest flex items-center gap-2">
                        <TerminalIcon size={12} /> Rust_Kernel_Output
