                </div>
                <div className="h-80 bg-black/80 rounded-xl border border-white/5 p-3 font-mono text-[9px] space-y-2 overflow-y-auto custom-scrollbar">
                    {logs.map((log, i) => (
                        <div key={i} className="flex gap-2">
                            <span className="text-zinc-700 shrink-0">{new Date(log.t).toLocaleTimeString([], {hour12:false, hour:'2-digit', minute:'2-digit', second:'2-digit'})}</span>
                            <span className={`
                                ${log.s === 'rust' ? 'text-[#e2e2e2] font-semibold' : ''}
                                ${log.s === 'sec' ? 'text-aegis-accent' : ''}
                                ${log.s === 'error' ? 'text-aegis-error' : ''}
                                ${log.s === 'info' ? 'text-zinc-600' : ''}
                            `}>
