import { GoogleGenAI, Type } from "@google/genai";
import { Artifact, Message, ReasoningMode } from "../types";

const getClient = () => {
  return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

const SYSTEM_INSTRUCTION = `
You are the NEXUS Synthesis Agent, the output layer of a distributed, multi-agent microservice architecture.
The system uses a high-performance Rust-based core for initial reasoning and OPA (Open Policy Agent) for security enforcement.

Your context consists of artifacts vaulted in the system's memory and processed by the Multimodal Parser Agent.
When responding:
- Reference the specific agents or memory chunks used (e.g., "[Verified by OPA_SEC]", "[Retrieved from Memory_Bank]").
- Maintain the persona of a secure, technical reasoning substrate.
- Use structured, clean Markdown.
- If complex data (CSV) is present, explain the trends. The UI will render charts automatically.
- Distinguish clearly between data-backed facts and inferred hypotheses.
`;

export const generateResponse = async (
  history: Message[],
  artifacts: Artifact[],
  mode: ReasoningMode,
  lastUserMessage: string
): Promise<string> => {
  const ai = getClient();
  const modelName = mode === 'pro' ? 'gemini-3-pro-preview' : 'gemini-3-flash-preview';

  const contentParts: any[] = [];

  if (artifacts.length > 0) {
    contentParts.push({ text: "[SYSTEM_MEMORY_DUMP]\n" });
    for (const art of artifacts) {
        if (art.type === 'image' && art.mimeType) {
            contentParts.push({
                inlineData: {
                    mimeType: art.mimeType,
                    data: art.content
                }
            });
            contentParts.push({ text: `[Artifact Reference: ${art.name}]` });
        } else if (art.type === 'csv' || art.type === 'text') {
            contentParts.push({ text: `[File: ${art.name}]\n${art.content}\n---` });
        }
    }
  }

  contentParts.push({ text: lastUserMessage });

  const tools: any[] = [];
  if (mode === 'flash') tools.push({ googleSearch: {} });

  let thinkingConfig = undefined;
  if (mode === 'pro') thinkingConfig = { thinkingBudget: 4096 };

  try {
    const response = await ai.models.generateContent({
      model: modelName,
      contents: { role: 'user', parts: contentParts },
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        tools: tools.length > 0 ? tools : undefined,
        thinkingConfig: thinkingConfig,
      }
    });

    let finalText = response.text || "";

    if (response.candidates?.[0]?.groundingMetadata?.groundingChunks) {
        const chunks = response.candidates[0].groundingMetadata.groundingChunks;
        const links = chunks
            .map((c: any) => c.web?.uri ? `[${c.web.title || 'Source'}](${c.web.uri})` : null)
            .filter(Boolean)
            .join(', ');
        if (links) finalText += `\n\n**Grounding Sources:** ${links}`;
    }

    return finalText;
  } catch (error: any) {
    console.error("Gemini API Error:", error);
    return `### ⚠️ ENGINE_ERROR\n\nReasoning cycle aborted: ${error.message}`;
  }
};

export type ArtifactType = 'text' | 'image' | 'csv' | 'audio';

export interface Artifact {
  id: string;
  name: string;
  type: ArtifactType;
  content: string; // Text content or Base64 string
  mimeType?: string;
  createdAt: number;
}

export type Role = 'user' | 'model';

export type MessageType = 'chat' | 'research_card' | 'security_alert';

export interface Message {
  id: string;
  role: Role;
  text: string;
  timestamp: number;
  type?: MessageType;
  metadata?: {
    confidence?: number;
    source?: string;
    agent?: string;
    phase?: ResearchPhase;
  };
  relatedArtifactIds?: string[];
}

export type ResearchPhase = 'IDLE' | 'PLANNING' | 'COLLECTION' | 'ANALYSIS' | 'SYNTHESIS';

export type ReasoningMode = 'flash' | 'pro';

export type AgentId = 'ORCHESTRATOR' | 'LIT_AGENT' | 'CRITIC' | 'SCRIBE' | 'SEC_OPA';

export interface AgentState {
  id: AgentId;
  name: string;
  status: 'IDLE' | 'ACTIVE' | 'ERROR';
  load: number;
}

import React, { useState, useEffect, useRef } from 'react';
import { 
  Bot, 
  Cpu, 
  Zap, 
  Send, 
  Paperclip, 
  Trash2, 
  Plus,
  Loader2,
  Database,
  Menu,
  X,
  Shield,
  ShieldCheck,
  ShieldAlert,
  Activity,
  Terminal as TerminalIcon,
  HardDrive,
  Globe,
  Sparkles,
  Command,
  Box,
  Fingerprint,
  ClipboardCheck,
  Search,
  BookOpen,
  Edit3,
  GitBranch,
  History
} from 'lucide-react';
import ReactMarkdown from 'react-markdown';
import { Prism as SyntaxHighlighter } from 'react-syntax-highlighter';
import { vscDarkPlus } from 'react-syntax-highlighter/dist/esm/styles/prism';

import { Artifact, Message, ReasoningMode, AgentState, AgentId, ResearchPhase } from './types';
import * as DBService from './services/db';
import * as GeminiService from './services/gemini';
import * as SecurityService from './services/security';
import { ChartRenderer } from './components/ChartRenderer';

function App() {
  const [messages, setMessages] = useState<Message[]>([]);
  const [artifacts, setArtifacts] = useState<Artifact[]>([]);
  const [inputText, setInputText] = useState('');
  const [mode, setMode] = useState<ReasoningMode>('pro');
  const [activePhase, setActivePhase] = useState<ResearchPhase>('IDLE');
  const [isProcessing, setIsProcessing] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isMonitorOpen, setIsMonitorOpen] = useState(false);
  const [securityStatus, setSecurityStatus] = useState<'idle' | 'scanning' | 'safe' | 'alert'>('idle');
  const [systemMetrics, setSystemMetrics] = useState({ cpu: 8, ram: 42, latency: 98, uptime: '00:00:00' });
  const [logs, setLogs] = useState<{ t: number, m: string, s: 'info'|'warn'|'error'|'sec'|'rust' }[]>([]);
  const [agents, setAgents] = useState<AgentState[]>([
    { id: 'ORCHESTRATOR', name: 'Research Orchestrator', status: 'IDLE', load: 0 },
    { id: 'LIT_AGENT', name: 'Lit & Web Agent', status: 'IDLE', load: 0 },
    { id: 'CRITIC', name: 'Analysis & Critique', status: 'IDLE', load: 0 },
    { id: 'SCRIBE', name: 'Synthesis Scribe', status: 'IDLE', load: 0 },
    { id: 'SEC_OPA', name: 'SEC_OPA Policy', status: 'IDLE', load: 0 }
  ]);

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const startTime = useRef(Date.now());

  useEffect(() => {
    loadArtifacts();
    addLog('NEXUS Research Kernel V5.0 Online', 'rust');
    addLog('Agents synchronized: ORCH, LIT, CRIT, SCRIB', 'sec');

    const interval = setInterval(() => {
        const diff = Date.now() - startTime.current;
        const h = Math.floor(diff / 3600000).toString().padStart(2, '0');
        const m = Math.floor((diff % 3600000) / 60000).toString().padStart(2, '0');
        const s = Math.floor((diff % 60000) / 1000).toString().padStart(2, '0');

        setSystemMetrics(prev => ({
            cpu: Math.floor(Math.random() * 8) + 4,
            ram: 41 + (Math.sin(diff / 8000) * 1.5),
            latency: 90 + Math.floor(Math.random() * 30),
            uptime: `${h}:${m}:${s}`
        }));
    }, 1500);
    return () => clearInterval(interval);
  }, []);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const addLog = (m: string, s: 'info'|'warn'|'error'|'sec'|'rust' = 'info') => {
      setLogs(prev => [{ t: Date.now(), m, s }, ...prev].slice(0, 100));
  };

  const updateAgent = (id: AgentId, status: 'IDLE' | 'ACTIVE' | 'ERROR', load: number) => {
      setAgents(prev => prev.map(a => a.id === id ? { ...a, status, load } : a));
  };

  const loadArtifacts = async () => {
    const items = await DBService.getAllArtifacts();
    setArtifacts(items);
  };

  const handleSendMessage = async () => {
    if (!inputText.trim() || isProcessing) return;

    setIsProcessing(true);
    setSecurityStatus('scanning');
    updateAgent('SEC_OPA', 'ACTIVE', 100);
    setActivePhase('PLANNING');
    addLog('Policy check initiated...', 'sec');

    const securityCheck = await SecurityService.validateInput(inputText);
    if (securityCheck.status === 'MALICIOUS') {
        updateAgent('SEC_OPA', 'ERROR', 0);
        setSecurityStatus('alert');
        addLog('POLICY_VIOLATION: Input rejected.', 'error');
        setMessages(prev => [...prev, {
            id: Date.now().toString(),
            role: 'model',
            text: `### 🔴 POLICY ALERT\n\nThe requested directive violates the NEXUS safety protocol. Context access has been revoked for this session.`,
            timestamp: Date.now(),
            type: 'security_alert'
        }]);
        setIsProcessing(false);
        setActivePhase('IDLE');
        return;
    }

    setSecurityStatus('safe');
    updateAgent('SEC_OPA', 'IDLE', 0);
    updateAgent('ORCHESTRATOR', 'ACTIVE', 80);
    addLog('[ORCH] Planning research sub-tasks...', 'rust');

    const userMsg: Message = {
      id: Date.now().toString(),
      role: 'user',
      text: inputText,
      timestamp: Date.now(),
      type: 'chat'
    };

    setMessages(prev => [...prev, userMsg]);
    setInputText('');

    try {
      // Step 2: Collection
      await new Promise(r => setTimeout(r, 1200));
      setActivePhase('COLLECTION');
      updateAgent('ORCHESTRATOR', 'IDLE', 0);
      updateAgent('LIT_AGENT', 'ACTIVE', 95);
      addLog('[LIT] Fetching groundings and memory chunks...', 'rust');

      // Step 3: Analysis
      await new Promise(r => setTimeout(r, 1500));
      setActivePhase('ANALYSIS');
      updateAgent('LIT_AGENT', 'IDLE', 0);
      updateAgent('CRITIC', 'ACTIVE', 90);
      addLog('[CRIT] Finding contradictions and gaps...', 'rust');

      // Step 4: Synthesis (Actual Gemini Call)
      setActivePhase('SYNTHESIS');
      updateAgent('CRITIC', 'IDLE', 0);
      updateAgent('SCRIBE', 'ACTIVE', 100);
      addLog('[SCRIBE] Generating final research synthesis...', 'rust');

      const responseText = await GeminiService.generateResponse(
        messages,
        artifacts,
        mode,
        userMsg.text
      );

      const botMsg: Message = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: responseText,
        timestamp: Date.now(),
        type: responseText.includes('###') ? 'chat' : 'research_card'
      };

      setMessages(prev => [...prev, botMsg]);
      addLog(`[NEXUS] Synthesis complete. Loop ended.`, 'rust');
    } catch (error: any) {
      addLog(`Loop failure: ${error.message}`, 'error');
    } finally {
      setIsProcessing(false);
      setActivePhase('IDLE');
      setAgents(prev => prev.map(a => ({ ...a, status: 'IDLE', load: 0 })));
      setTimeout(() => setSecurityStatus('idle'), 3000);
    }
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;
    updateAgent('LIT_AGENT', 'ACTIVE', 100);

    for (let i = 0; i < files.length; i++) {
      const file = files[i];
      addLog(`Indexing artifact: ${file.name}`, 'rust');
      const reader = new FileReader();
      reader.onload = async (ev) => {
        const result = ev.target?.result as string;
        let type: Artifact['type'] = 'text';
        let content = result;
        if (file.type.startsWith('image/')) {
            type = 'image';
            content = result.split(',')[1];
        } else if (file.type === 'text/csv' || file.name.endsWith('.csv')) {
            type = 'csv';
        }
        const newArtifact: Artifact = {
          id: Date.now().toString() + Math.random().toString(),
          name: file.name,
          type,
          content,
          mimeType: file.type,
          createdAt: Date.now()
        };
        await DBService.saveArtifact(newArtifact);
        setArtifacts(prev => [...prev, newArtifact]);
        addLog(`Vaulted: ${newArtifact.name}`, 'sec');
        updateAgent('LIT_AGENT', 'IDLE', 0);
      };
      if (file.type.startsWith('image/')) reader.readAsDataURL(file);
      else reader.readAsText(file);
    }
  };

  return (
    <div className="flex h-[100dvh] w-full bg-[#030303] text-zinc-300 font-sans overflow-hidden relative selection:bg-aegis-accent/30 selection:text-white">

      <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,_rgba(0,112,243,0.02)_0%,_transparent_70%)] pointer-events-none" />
      <div className="scan-line" />

      {/* MOBILE OVERLAY */}
      {(isSidebarOpen || (isMonitorOpen && window.innerWidth < 1024)) && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-md z-[60] lg:hidden" onClick={() => { setIsSidebarOpen(false); setIsMonitorOpen(false); }} />
      )}

      {/* LEFT SIDEBAR: Context Memory */}
      <div className={`
        fixed inset-y-0 left-0 z-[70] w-[80%] sm:w-64 glass border-r border-white/5 flex flex-col transform transition-all duration-300 ease-in-out
        ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'} md:relative md:translate-x-0
      `}>
        <div className="p-4 border-b border-white/5 bg-black/20 flex items-center justify-between">
            <div className="flex items-center gap-2">
                <Box size={14} className="text-aegis-accent" />
                <span className="text-[10px] font-bold tracking-[0.2em] font-mono text-zinc-500 uppercase">Memory_Vault</span>
            </div>
            <button onClick={() => fileInputRef.current?.click()} className="p-1.5 hover:bg-white/5 rounded-md text-zinc-400">
                <Plus size={16} />
            </button>
            <input type="file" ref={fileInputRef} className="hidden" multiple onChange={handleFileUpload} />
        </div>

        <div className="flex-1 overflow-y-auto p-3 space-y-2 custom-scrollbar">
            {artifacts.map(art => (
                <div key={art.id} className="group glass border border-white/5 rounded-lg p-3 hover:border-aegis-accent/30 transition-all cursor-default relative overflow-hidden">
                    <div className="flex items-center gap-2 mb-1.5">
                        <Fingerprint size={12} className="text-aegis-accent/60" />
                        <span className="text-[11px] font-mono font-bold truncate tracking-tight">{art.name}</span>
                    </div>
                    <div className="flex justify-between items-center text-[9px] font-mono text-zinc-500">
                        <span className="opacity-50 uppercase">{art.type}</span>
                        <button onClick={() => DBService.deleteArtifact(art.id).then(loadArtifacts)} className="opacity-0 group-hover:opacity-100 p-1 text-zinc-600 hover:text-aegis-error transition-opacity">
                            <X size={10} />
